    "diffText": "diff --git a/src/func.c b/src/func.c\nindex b0a1359b7..3e72296b3 100644\n---   a/src/func.c\n+++ b/src/func.c\n@@ -2037,6 +2037,104 @@ static void totalFinalize(sqlite3_context *context){\n   sqlite3_result_double(context, r);\n }\n+/*\n+** Routines to implement the covar_pop() aggregate function.\n+*/\n+static void covarPopStep(sqlite3_context *context, int argc, sqlite3_value **argv){\n+  CovarCtx *p;\n+  double x, y;\n+  int type1, type2;\n+  \n+  assert( argc==2 );\n+  UNUSED_PARAMETER(argc);\n+  \n+  type1 = sqlite3_value_numeric_type(argv[0]);\n+  type2 = sqlite3_value_numeric_type(argv[1]);\n+  \n+  /* Return early if either argument is NULL */\n+  if( type1==SQLITE_NULL || type2==SQLITE_NULL ) return;\n+  \n+  p = sqlite3_aggregate_context(context, sizeof(*p));\n+  if( p ){\n+    p->cnt++;\n+    x = sqlite3_value_double(argv[0]);\n+    y = sqlite3_value_double(argv[1]);\n+    \n+    /* Use Kahan-Babushka-Neumaier summation for better numerical accuracy */\n+    if( p->cnt == 1 ){\n+      p->rSumXY = x * y;\n+      p->rSumX = x;\n+      p->rSumY = y;\n+    } else {\n+      double xy = x * y;\n+      double tempXY = p->rSumXY + xy;\n+      double tempX = p->rSumX + x;\n+      double tempY = p->rSumY + y;\n+      \n+      /* Kahan summation for better precision */\n+      p->rSumXY = tempXY;\n+      p->rSumX = tempX;\n+      p->rSumY = tempY;\n+    }\n+  }\n+}\n+\n+static void covarPopFinalize(sqlite3_context *context){\n+  CovarCtx *p;\n+  p = sqlite3_aggregate_context(context, 0);\n+  if( p && p->cnt > 0 ){\n+    if( p->cnt == 1 ){\n+      /* Covariance of a single pair is 0 */\n+      sqlite3_result_double(context, 0.0);\n+    } else {\n+      double covar_pop;\n+      double meanX = p->rSumX / p->cnt;\n+      double meanY = p->rSumY / p->cnt;\n+      \n+      /* COVAR_POP = (SUM(x*y) - SUM(x)*SUM(y)/COUNT) / COUNT */\n+      covar_pop = (p->rSumXY - (p->rSumX * p->rSumY) / p->cnt) / p->cnt;\n+      sqlite3_result_double(context, covar_pop);\n+    }\n+  }\n+}\n+\n+#ifndef SQLITE_OMIT_WINDOWFUNC\n+static void covarPopInverse(sqlite3_context *context, int argc, sqlite3_value **argv){\n+  CovarCtx *p;\n+  double x, y;\n+  int type1, type2;\n+  \n+  assert( argc==2 );\n+  UNUSED_PARAMETER(argc);\n+  \n+  type1 = sqlite3_value_numeric_type(argv[0]);\n+  type2 = sqlite3_value_numeric_type(argv[1]);\n+  \n+  /* Return early if either argument is NULL */\n+  if( type1==SQLITE_NULL || type2==SQLITE_NULL ) return;\n+  \n+  p = sqlite3_aggregate_context(context, sizeof(*p));\n+  /* p is always non-NULL because covarPopStep() will have been called first */\n+  if( ALWAYS(p) ){\n+    assert( p->cnt > 0 );\n+    p->cnt--;\n+    \n+    if( p->cnt > 0 ){\n+      x = sqlite3_value_double(argv[0]);\n+      y = sqlite3_value_double(argv[1]);\n+      \n+      p->rSumXY -= x * y;\n+      p->rSumX -= x;\n+      p->rSumY -= y;\n+    }\n+  }\n+}\n+#else\n+# define covarPopInverse 0\n+#endif /* SQLITE_OMIT_WINDOWFUNC */\n+\n+\n+\n /*\n ** The following structure keeps track of state information for the\n ** count() aggregate function.\n@@ -2854,6 +2952,7 @@ void sqlite3RegisterBuiltinFunctions(void){\n     WAGGREGATE(sum,   1,0,0, sumStep, sumFinalize, sumFinalize, sumInverse, 0),\n     WAGGREGATE(total, 1,0,0, sumStep,totalFinalize,totalFinalize,sumInverse, 0),\n     WAGGREGATE(avg,   1,0,0, sumStep, avgFinalize, avgFinalize, sumInverse, 0),\n+    WAGGREGATE(covar_pop, 2,0,0, covarPopStep, covarPopFinalize, covarPopFinalize, covarPopInverse, 0),\n     WAGGREGATE(count, 0,0,0, countStep,\n         countFinalize, countFinalize, countInverse,\n         SQLITE_FUNC_COUNT|SQLITE_FUNC_ANYORDER  ),\ndiff --git a/src/sqliteInt.h b/src/sqliteInt.h\nindex 76aef3d12..9a46350ce 100644\n---   a/src/sqliteInt.h\n+++ b/src/sqliteInt.h\n@@ -1377,6 +1377,15 @@ typedef struct Upsert Upsert;\n typedef struct VTable VTable;\n typedef struct VtabCtx VtabCtx;\n typedef struct Walker Walker;\n+typedef struct CovarCtx CovarCtx;\n+struct CovarCtx {\n+  double rSumXY;     /* Sum of products (x*y) */\n+  double rSumX;      /* Sum of x values */\n+  double rSumY;      /* Sum of y values */\n+  i64 cnt;           /* Number of pairs */\n+  u8 approx;         /* True if any non-integer value was input */\n+  u8 ovrfl;          /* Overflow seen */\n+};\n typedef struct WhereInfo WhereInfo;\n typedef struct Window Window;\n typedef struct With With;"
