    "diffText": "diff --git a/src/func.c b/src/func.c\nindex b0a1359b7..592326c39 100644\n---   a/src/func.c\n+++ b/src/func.c\n@@ -2333,6 +2333,7 @@ static void groupConcatValue(sqlite3_context *context){\n ** of the built-in functions above are part of the global function set.\n ** This routine only deals with those that are not global.\n */\n+\n void sqlite3RegisterPerConnectionBuiltinFunctions(sqlite3 *db){\n   int rc = sqlite3_overload_function(db, \"MATCH\", 2);\n   assert( rc==SQLITE_NOMEM || rc==SQLITE_OK );\n@@ -2618,6 +2619,65 @@ static void piFunc(\n #endif /* SQLITE_ENABLE_MATH_FUNCTIONS */\n+/*\n+** Implementation of lcm(X,Y) function.\n+**\n+** Computes the least common multiple of X and Y\n+*/\n+static void lcmFunc(\n+  sqlite3_context *context,\n+  int argc,\n+  sqlite3_value **argv\n+){\n+  i64 x, y;\n+  i64 gcd, lcm;\n+  \n+  assert(argc == 2);\n+  \n+  if (sqlite3_value_type(argv[0]) == SQLITE_NULL || sqlite3_value_type(argv[1]) == SQLITE_NULL) {\n+    sqlite3_result_null(context);\n+    return;\n+  }\n+  \n+  x = sqlite3_value_int64(argv[0]);\n+  y = sqlite3_value_int64(argv[1]);\n+  \n+  if (x == 0 || y == 0) {\n+    sqlite3_result_int64(context, 0);\n+    return;\n+  }\n+  \n+  /* Compute GCD using Euclidean algorithm */\n+  i64 a = x < 0 ? -x : x;\n+  i64 b = y < 0 ? -y : y;\n+  while (b != 0) {\n+    i64 temp = b;\n+    b = a % b;\n+    a = temp;\n+  }\n+  gcd = a;\n+  \n+  /* Compute LCM using the formula: LCM(x,y) = |x*y| / GCD(x,y) */\n+  /* To prevent overflow, we divide first */\n+  if (gcd == 0) {\n+    sqlite3_result_error(context, \"division by zero in lcm calculation\", -1);\n+    return;\n+  }\n+  \n+  i64 abs_x = x < 0 ? -x : x;\n+  i64 abs_y = y < 0 ? -y : y;\n+  i64 quotient = abs_x / gcd;\n+  \n+  /* Check for overflow before multiplication */\n+  if (quotient > LARGEST_INT64 / abs_y) {\n+    sqlite3_result_error(context, \"integer overflow in lcm calculation\", -1);\n+    return;\n+  }\n+  \n+  lcm = quotient * abs_y;\n+  sqlite3_result_int64(context, lcm);\n+}\n+\n /*\n ** Implementation of sign(X) function.\n */\n@@ -2914,6 +2974,7 @@ void sqlite3RegisterBuiltinFunctions(void){\n     MFUNCTION(pi,                0, 0,         piFunc      ),\n #endif /* SQLITE_ENABLE_MATH_FUNCTIONS */\n     FUNCTION(sign,               1, 0, 0,      signFunc    ),\n+    FUNCTION(lcm,                2, 0, 0,      lcmFunc     ),\n     INLINE_FUNC(coalesce,       -4, INLINEFUNC_coalesce, 0 ),\n     INLINE_FUNC(iif,            -4, INLINEFUNC_iif,      0 ),\n     INLINE_FUNC(if,             -4, INLINEFUNC_iif,      0 ),"
